import { useState } from 'react';
import { formatPhone, normalizePhone } from '../../utils/phone';
import styles from './Input.module.css';

const EyeOpen = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
    stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
    <circle cx="12" cy="12" r="3"/>
  </svg>
);

const EyeOff = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
    stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19m-6.72-1.07a3 3 0 11-4.24-4.24"/>
    <line x1="1" y1="1" x2="23" y2="23"/>
  </svg>
);

export function Input({
  label,
  type = 'text',
  value,
  onChange,
  error,
  placeholder,
  disabled,
  maxLength,
  autoComplete,
  inputMode,
}) {
  const [showPass, setShowPass] = useState(false);
  const isPassword = type === 'password';
  const isPhone = type === 'phone';

  const handleChange = (e) => {
    if (isPhone) {
      const raw = e.target.value;
      const digits = raw.replace(/\D/g, '');
      const limited = digits.slice(0, 11);
      const formatted = formatPhone(limited);
      onChange(formatted, normalizePhone(formatted));
    } else if (isPassword) {
      // Allow only ASCII printable characters (no Cyrillic / non-Latin scripts)
      const filtered = e.target.value.replace(/[^\x20-\x7E]/g, '');
      onChange(filtered);
    } else {
      onChange(e.target.value);
    }
  };

  return (
    <div className={styles.wrapper}>
      {label && <label className={styles.label}>{label}</label>}
      <div className={styles.inputRow}>
        <input
          className={`${styles.input} ${isPassword ? styles.inputWithEye : ''} ${error ? styles.inputError : ''}`}
          type={isPassword ? (showPass ? 'text' : 'password') : isPhone ? 'tel' : type}
          value={value}
          onChange={handleChange}
          placeholder={placeholder}
          disabled={disabled}
          maxLength={maxLength || (isPhone ? 18 : undefined)}
          autoComplete={autoComplete}
          inputMode={isPhone ? 'numeric' : inputMode}
        />
        {isPassword && (
          <button
            type="button"
            className={styles.eyeBtn}
            onClick={() => setShowPass((p) => !p)}
            tabIndex={-1}
          >
            {showPass ? <EyeOff /> : <EyeOpen />}
          </button>
        )}
      </div>
      {error && <span className={styles.error}>{error}</span>}
    </div>
  );
}
